import React from 'react';
import { Link } from 'react-router-dom';
import './CoreFeatures.css';

const CoreFeatures = () => {
  const features = [
    {
      icon: '📚',
      title: 'Comprehensive Assessment',
      description: 'Create and manage various types of assessments including multiple-choice, descriptive, and practical tests.',
      benefits: ['Flexible question types', 'Automated grading', 'Detailed analytics']
    },
    {
      icon: '📊',
      title: 'Advanced Analytics',
      description: 'Get detailed insights into student performance with comprehensive reports and visualizations.',
      benefits: ['Performance tracking', 'Skill assessment', 'Progress monitoring']
    },
    {
      icon: '👥',
      title: 'Multi-Role Management',
      description: 'Support for students, teachers, and administrators with role-specific dashboards and permissions.',
      benefits: ['Role-based access', 'Customized interfaces', 'Secure permissions']
    },
    {
      icon: '🎯',
      title: 'Skill-Based Evaluation',
      description: 'Evaluate students across multiple cognitive skills including analytical thinking and problem-solving.',
      benefits: ['Cognitive skill mapping', 'Personalized feedback', 'Skill development']
    },
    {
      icon: '📱',
      title: 'User-Friendly Interface',
      description: 'Modern, intuitive design that makes the platform accessible for users of all technical levels.',
      benefits: ['Responsive design', 'Easy navigation', 'Clean aesthetics']
    },
    {
      icon: '🔒',
      title: 'Secure & Reliable',
      description: 'Enterprise-grade security with data protection and reliable performance for academic institutions.',
      benefits: ['Data encryption', 'Regular backups', 'High availability']
    }
  ];

  return (
    <div className="core-features-page">
      {/* Hero Section */}
      <section className="features-hero">
        <div className="container">
          <div className="hero-content">
            <h1>Core Platform Features</h1>
            <p>Everything you need to manage your academic ecosystem efficiently.</p>
            <div className="hero-breadcrumb">
              <Link to="/">Home</Link>
              <span className="separator">/</span>
              <span className="current">Core Features</span>
            </div>
          </div>
        </div>
      </section>

      {/* Features Grid */}
      <section className="features-content">
        <div className="container">
          <div className="features-grid">
            {features.map((feature, index) => (
              <div key={index} className="feature-card">
                <div className="feature-icon">
                  <span className="icon-emoji">{feature.icon}</span>
                </div>
                <div className="feature-content">
                  <h3>{feature.title}</h3>
                  <p className="feature-description">{feature.description}</p>
                  <ul className="feature-benefits">
                    {feature.benefits.map((benefit, benefitIndex) => (
                      <li key={benefitIndex}>{benefit}</li>
                    ))}
                  </ul>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="features-cta">
        <div className="container">
          <div className="cta-content">
            <h2>Ready to Transform Your Educational Experience?</h2>
            <p>Join thousands of educators and students already using our platform.</p>
            <div className="cta-buttons">
              <Link to="/register" className="btn btn-primary">Get Started</Link>
              <Link to="/login" className="btn btn-outline">Sign In</Link>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default CoreFeatures;
